1	import { Component, computed, inject, OnInit, signal } from '@angular/core';
2	import { FormsModule } from '@angular/forms';
3	import { MatButtonModule } from '@angular/material/button';
4	import { MatCheckboxModule } from '@angular/material/checkbox';
5	import {
6	    MAT_DIALOG_DATA,
7	    MatDialogModule,
8	    MatDialogRef,
9	} from '@angular/material/dialog';
10	import { MatFormFieldModule } from '@angular/material/form-field';
11	import { MatIconModule } from '@angular/material/icon';
12	import { MatInputModule } from '@angular/material/input';
13	import { MatProgressSpinnerModule } from '@angular/material/progress-spinner';
14	import { MatSnackBar } from '@angular/material/snack-bar';
15	import { TranslatePipe } from '@ngx-translate/core';
16	import { DatabaseService, XCategoryFromDb } from 'services';
17	import { createLogger } from '@iptvnator/portal/shared/util';
18	
19	export interface CategoryManagementDialogData {
20	    playlistId: string;
21	    contentType: 'live' | 'vod' | 'series';
22	    itemCounts: Map<number, number>;
23	}
24	
25	interface CategoryWithSelection extends XCategoryFromDb {
26	    selected: boolean;
27	}
28	
29	@Component({
30	    selector: 'app-category-management-dialog',
31	    imports: [
32	        MatDialogModule,
33	        MatButtonModule,
34	        MatCheckboxModule,
35	        MatFormFieldModule,
36	        MatIconModule,
37	        MatInputModule,
38	        MatProgressSpinnerModule,
39	        FormsModule,
40	        TranslatePipe,
41	    ],
42	    templateUrl: './category-management-dialog.component.html',
43	    styleUrl: './category-management-dialog.component.scss',
44	})
45	export class CategoryManagementDialogComponent implements OnInit {
46	    private readonly dbService = inject(DatabaseService);
47	    private readonly dialogRef = inject(
48	        MatDialogRef<CategoryManagementDialogComponent>
49	    );
50	    readonly data = inject<CategoryManagementDialogData>(MAT_DIALOG_DATA);
51	    private readonly logger = createLogger('CategoryManagementDialog');
52	
53	    readonly isLoading = signal(true);
54	    readonly isSaving = signal(false);
55	    readonly categories = signal<CategoryWithSelection[]>([]);
56	    readonly searchTerm = signal('');
57	
58	    readonly filteredCategories = computed(() => {
59	        const term = this.searchTerm().toLowerCase();
60	        if (!term) return this.categories();
61	        return this.categories().filter((c) =>
62	            c.name.toLowerCase().includes(term)
63	        );
64	    });
65	
66	    readonly selectedCount = computed(
67	        () => this.categories().filter((c) => c.selected).length
68	    );
69	
70	    readonly totalCount = computed(() => this.categories().length);
71	
72	    readonly allSelected = computed(
73	        () =>
74	            this.categories().length > 0 &&
75	            this.categories().every((c) => c.selected)
76	    );
77	
78	    readonly someSelected = computed(
79	        () => this.categories().some((c) => c.selected) && !this.allSelected()
80	    );
81	
82	    async ngOnInit(): Promise<void> {
83	        await this.loadCategories();
84	    }
85	
86	    private async loadCategories(): Promise<void> {
87	        try {
88	            const type = this.getDbType();
89	            const allCategories = await this.waitForCategories(type);
90	            this.categories.set(
91	                allCategories.map((c) => ({
92	                    ...c,
93	                    selected: !c.hidden,
94	                }))
95	            );
96	        } catch (error) {
97	            this.logger.error('Error loading categories', error);
98	        } finally {
99	            this.isLoading.set(false);
100	        }
101	    }
102	
103	    private async waitForCategories(
104	        type: 'live' | 'movies' | 'series'
105	    ): Promise<XCategoryFromDb[]> {
106	        const retryDeadlineMs = Date.now() + 10000;
107	        const expectedCategoryCount = this.data.itemCounts.size;
108	
109	        while (true) {
110	            const categories = await this.dbService.getAllXtreamCategories(
111	                this.data.playlistId,
112	                type
113	            );
114	
115	            if (
116	                categories.length > 0 ||
117	                expectedCategoryCount === 0 ||
118	                Date.now() >= retryDeadlineMs
119	            ) {
120	                return categories;
121	            }
122	
123	            await new Promise((resolve) => setTimeout(resolve, 250));
124	        }
125	    }
126	
127	    clearSearch(): void {
128	        this.searchTerm.set('');
129	    }
130	
131	    getItemCount(category: CategoryWithSelection): number {
132	        const categoryId = Number(category.id);
133	        return this.data.itemCounts.get(categoryId) ?? 0;
134	    }
135	
136	    private getDbType(): 'live' | 'movies' | 'series' {
137	        switch (this.data.contentType) {
138	            case 'live':
139	                return 'live';
140	            case 'vod':
141	                return 'movies';
142	            case 'series':
143	                return 'series';
144	        }
145	    }
146	
147	    toggleCategory(category: CategoryWithSelection): void {
148	        this.categories.update((cats) =>
149	            cats.map((c) =>
150	                c.id === category.id ? { ...c, selected: !c.selected } : c
151	            )
152	        );
153	    }
154	
155	    selectAll(): void {
156	        this.categories.update((cats) =>
157	            cats.map((c) => ({ ...c, selected: true }))
158	        );
159	    }
160	
161	    deselectAll(): void {
162	        this.categories.update((cats) =>
163	            cats.map((c) => ({ ...c, selected: false }))
164	        );
165	    }
166	
167	    toggleAll(): void {
168	        if (this.allSelected()) {
169	            this.deselectAll();
170	        } else {
171	            this.selectAll();
172	        }
173	    }
174	
175	    async save(): Promise<void> {
176	        this.isSaving.set(true);
177	        try {
178	            const categories = this.categories();
179	            const toHide = categories.filter((c) => !c.selected).map((c) => c.id);
180	            const toShow = categories.filter((c) => c.selected).map((c) => c.id);
181	
182	            if (toHide.length > 0) {
183	                await this.dbService.updateCategoryVisibility(toHide, true);
184	            }
185	            if (toShow.length > 0) {
186	                await this.dbService.updateCategoryVisibility(toShow, false);
187	            }
188	
189	            this.dialogRef.close(true);
190	        } catch (error) {
191	            this.logger.error('Error saving category visibility', error);
192	            inject(MatSnackBar).open(
193	                'Failed to save category visibility',
194	                'Close',
195	                { duration: 3000 }
196	            );
197	        } finally {
198	            this.isSaving.set(false);
199	        }
200	    }
