file.content:
::ng-deep .mat-mdc-dialog-content {
    overflow: hidden !important;
}

.mat-mdc-dialog-content {
    display: flex;
    gap: 10px;
    flex-direction: column;
}

.loading-container {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    padding: 40px;
    gap: 16px;
}

.header-actions {
    display: flex;
    justify-content: space-between;
    align-items: center;
    flex-wrap: wrap;
    gap: 12px;
}

.selection-info {
    font-size: 0.8125rem;
    color: var(--mat-sys-on-surface-variant);

    strong {
        color: var(--mat-sys-primary);
    }
}

.bulk-actions {
    display: flex;
    gap: 8px;

    button {
        font-size: 12px;
    }
}

.search-inline {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 0 10px;
    min-height: 36px;
    border-radius: 10px;
    border: 1px solid var(--app-search-border, var(--mat-sys-outline-variant));
    background: var(--app-search-bg, var(--mat-sys-surface-container));
    cursor: text;
    transition:
        border-color 0.15s ease,
        box-shadow 0.15s ease;

    &:focus-within {
        border-color: var(--mat-sys-primary);
        box-shadow: 0 0 0 3px
            color-mix(in srgb, var(--mat-sys-primary) 12%, transparent);
    }
}

.search-inline__icon {
    font-size: 18px;
    width: 18px;
    height: 18px;
    color: var(--mat-sys-on-surface-variant);
    flex-shrink: 0;
}

.search-inline input {
    flex: 1;
    border: none;
    outline: none;
    background: transparent;
    color: var(--mat-sys-on-surface);
    font: inherit;
    font-size: 0.84rem;
    width: 100%;
    min-width: 0;

    &::placeholder {
        color: var(--mat-sys-on-surface-variant);
        opacity: 0.6;
    }

    &::-webkit-search-cancel-button {
        display: none;
    }
}

.search-inline__clear {
    width: 24px;
    height: 24px;
    min-width: 24px;
    line-height: 24px;
    flex-shrink: 0;
    padding: 0;

    mat-icon {
        font-size: 16px;
        width: 16px;
        height: 16px;
    }
}

.categories-list {
    height: 450px;
    overflow-y: auto;
    border: 1px solid var(--mat-sys-outline-variant);
    border-radius: 8px;
}

.category-item {
    display: flex;
    align-items: center;
    padding: 2px 10px;
    cursor: pointer;
    gap: 8px;
    transition: background-color 0.12s ease;

    &:hover {
        background-color: var(--mat-sys-surface-container);
    }

    &:not(:last-child) {
        border-bottom: 1px solid var(--mat-sys-surface-container);
    }

    mat-checkbox {
        --mdc-checkbox-state-layer-size: 32px;
    }
}

.category-name {
    flex: 1;
    font-size: 0.8125rem;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.empty-message {
    padding: 24px;
    text-align: center;
    color: var(--mat-sys-on-surface-variant);
    font-size: 0.8125rem;
}

:host ::ng-deep {
    .mat-mdc-dialog-content {
        min-width: 480px;
        max-width: 600px;
        max-height: 75vh !important;
    }
}

mat-dialog-actions {
    button {
        mat-spinner {
            display: inline-block;
        }
    }
}

