        box-shadow 0.15s ease;

    &:focus-within {
        border-color: var(--mat-sys-primary);
        box-shadow: 0 0 0 3px
            color-mix(in srgb, var(--mat-sys-primary) 12%, transparent);
    }

    mat-icon {
        font-size: 18px;
        width: 18px;
        height: 18px;
        color: var(--mat-sys-on-surface-variant);
        flex-shrink: 0;
    }

    input {
        flex: 1;
        border: none;
        outline: none;
        background: transparent;
        color: var(--mat-sys-on-surface);
        font: inherit;
        font-size: 0.875rem;
        width: 100%;

        &::placeholder {
            color: var(--mat-sys-on-surface-variant);
            opacity: 0.7;
        }
    }
}

.palette-search__hint {
    font-size: 0.72rem;
    color: var(--mat-sys-on-surface-variant);
    border: 1px solid var(--app-separator, var(--mat-sys-outline-variant));
    border-radius: 6px;
    padding: 2px 6px;
    line-height: 1;
    flex-shrink: 0;
    background: var(
        --app-widget-header-bg,
        var(--mat-sys-surface-container-high)
    );
}

.palette-results {
    max-height: min(56vh, 520px);
    overflow: auto;
    margin-top: 12px;
    display: grid;
    gap: 10px;
    padding-right: 2px;
}

.palette-group {
    display: grid;
    gap: 6px;

    h3 {
        margin: 0;
        font-size: 0.74rem;
        color: var(--mat-sys-on-surface-variant);
        text-transform: uppercase;
        letter-spacing: 0.05em;
        font-weight: 620;
    }
}

.palette-group__items {
    display: grid;
    gap: 4px;
}

.palette-command {
    display: grid;
    gap: 1px;
    width: 100%;
    text-align: left;
    border: 1px solid transparent;
    border-radius: 10px;
    background: transparent;
    color: inherit;
    padding: 8px 10px;
    cursor: pointer;

    &:hover:not(:disabled),
    &.is-selected:not(:disabled) {
        background: linear-gradient(
            145deg,
            var(--app-selection-surface-strong),
            var(--app-selection-surface)
        );
        border-color: var(--app-selection-border);
    }

    &:disabled {
        cursor: not-allowed;
        opacity: 0.45;
    }
}

.palette-command--with-icon {
    grid-template-columns: auto minmax(0, 1fr);
    align-items: center;
    gap: 10px;
}

.palette-command__icon {
    width: 30px;
    height: 30px;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    border-radius: 9px;
    background: color-mix(
        in srgb,
        var(--app-selection-surface-strong) 72%,
        transparent
    );
    color: var(--app-selection-color);
    flex-shrink: 0;

    mat-icon {
        font-size: 18px;
        width: 18px;
        height: 18px;
    }
}

.palette-command__content {
    min-width: 0;
    display: grid;
    gap: 1px;
}

.palette-command__label {
    font-size: 0.9rem;
    font-weight: 560;
    letter-spacing: -0.006em;
}

.palette-command__description {
    font-size: 0.76rem;
    color: var(--mat-sys-on-surface-variant);
}

.palette-empty {
    border: 1px dashed var(--mat-sys-outline-variant);
    border-radius: 10px;
    padding: 18px;
    text-align: center;
    color: var(--mat-sys-on-surface-variant);
    font-size: 0.88rem;
}

