296	    onItemCardKeydown(event: KeyboardEvent, item: DownloadItem): void {
297	        if (event.target !== event.currentTarget) {
298	            return;
299	        }
300	
301	        if (event.key !== 'Enter' && event.key !== ' ') {
302	            return;
303	        }
304	
305	        event.preventDefault();
306	        void this.openInLibrary(item);
307	    }
308	
309	    async openInLibrary(item: DownloadItem): Promise<void> {
310	        if (!this.hasSourcePlaylist(item)) {
311	            this.snackBar.open(
312	                this.translate.instant('DOWNLOADS.SOURCE_PLAYLIST_MISSING'),
313	                undefined,
314	                { duration: 3000, horizontalPosition: 'start' }
315	            );
316	            return;
317	        }
318	
319	        if (!this.isItemNavigable(item)) {
320	            return;
321	        }
322	
323	        const source = await this.resolveSourceType(item.playlistId);
324	        if (!source) {
325	            return;
326	        }
327	
328	        if (source === 'xtream') {
329	            await this.openXtreamItem(item);
330	            return;
331	        }
332	
333	        await this.openStalkerItem(item);
334	    }
335	
336	    private getTargetContentId(item: DownloadItem): number | null {
337	        const id =
338	            item.contentType === 'episode'
339	                ? (item.seriesXtreamId ?? item.xtreamId)
340	                : item.xtreamId;
341	        const numeric = Number(id);
342	        return Number.isFinite(numeric) ? numeric : null;
343	    }
344	
345	    private buildPlaylistRoute(
346	        source: PortalSource,
347	        playlistId: string,
348	        segments: Array<string | number>
349	    ): Array<string | number> {
350	        const sourceSegment = source === 'stalker' ? 'stalker' : 'xtreams';
351	        return ['/workspace', sourceSegment, playlistId, ...segments];
352	    }
353	
354	    private async resolveSourceType(
355	        playlistId: string
356	    ): Promise<PortalSource | null> {
357	        try {
358	            const playlist = await firstValueFrom(
359	                this.playlistsService.getPlaylistById(playlistId)
360	            );
361	
362	            if (!playlist) {
363	                return null;
364	            }
365	
366	            if (playlist.portalUrl && playlist.macAddress) {
367	                return 'stalker';
368	            }
369	
370	            return 'xtream';
371	        } catch {
372	            return null;
373	        }
374	    }
375	
376	    private async openXtreamItem(item: DownloadItem): Promise<void> {
377	        const targetId = this.getTargetContentId(item);
378	        if (targetId === null) return;
379	
380	        const contentType = item.contentType === 'episode' ? 'series' : 'vod';
381	        const content = await this.dbService.getContentByXtreamId(
382	            targetId,
383	            item.playlistId
384	        );
385	        const categoryId = content?.category_id;
386	
387	        if (categoryId === null || categoryId === undefined) {
388	            await this.router.navigate(
389	                this.buildPlaylistRoute('xtream', item.playlistId, [
390	                    contentType,
391	                ])
392	            );
393	            return;
394	        }
395	
396	        await this.router.navigate(
397	            this.buildPlaylistRoute('xtream', item.playlistId, [
398	                contentType,
399	                String(categoryId),
400	                String(targetId),
401	            ])
402	        );
403	    }
404	
405	    private normalizePortalItemId(value: unknown): string {
406	        const raw = String(value ?? '').trim();
407	        if (!raw) return '';
408	        return raw.includes(':') ? raw.split(':')[0] : raw;
409	    }
410	
411	    private normalizeStalkerCategoryId(
412	        value: unknown,
413	        fallback: 'vod' | 'series'
414	    ): 'vod' | 'series' | 'itv' {
415	        const normalized = String(value ?? '').toLowerCase();
416	        if (normalized === 'movie') return 'vod';
417	        if (
418	            normalized === 'vod' ||
419	            normalized === 'series' ||
420	            normalized === 'itv'
421	        ) {
422	            return normalized;
423	        }
424	        return fallback;
425	    }
426	
427	    private findMatchingStalkerRecentItem(
428	        items: Array<Record<string, unknown>>,
429	        targetId: number
430	    ): Record<string, unknown> | undefined {
431	        const expectedId = String(targetId);
432	        return items.find((recentItem) => {
433	            const candidates = [
434	                recentItem['id'],
435	                recentItem['movie_id'],
436	                recentItem['series_id'],
437	                recentItem['stream_id'],
438	            ];
439	
440	            return candidates.some(
441	                (candidate) =>
442	                    this.normalizePortalItemId(candidate) === expectedId
443	            );
444	        });
445	    }
446	
447	    private async buildStalkerOpenState(
448	        item: DownloadItem,
449	        targetId: number,
450	        fallbackCategory: 'vod' | 'series'
451	    ): Promise<Record<string, unknown>> {
452	        try {
453	            const items = (await firstValueFrom(
454	                this.playlistsService.getPortalRecentlyViewed(item.playlistId)
455	            )) as Array<Record<string, unknown>>;
456	
457	            const matched = this.findMatchingStalkerRecentItem(items, targetId);
458	
459	            if (matched) {
460	                return {
461	                    ...matched,
462	                    id:
463	                        matched['id'] ??
464	                        matched['series_id'] ??
465	                        matched['movie_id'] ??
466	                        String(targetId),
467	                    category_id: this.normalizeStalkerCategoryId(
468	                        matched['category_id'],
469	                        fallbackCategory
470	                    ),
471	                    title: matched['title'] ?? item.title,
472	                    name: matched['name'] ?? matched['o_name'] ?? item.title,
473	                };
474	            }
475	        } catch {
476	            // Ignore and use fallback state below.
477	        }
478	
479	        return {
480	            id: String(targetId),
481	            category_id: fallbackCategory,
482	            title: item.title,
483	            name: item.title,
484	            o_name: item.title,
485	            cover: item.posterUrl,
486	            logo: item.posterUrl,
487	        };
488	    }
489	
490	    private async openStalkerItem(item: DownloadItem): Promise<void> {
491	        const targetId = this.getTargetContentId(item);
492	        if (targetId === null) return;
493	
494	        const fallbackCategory =
495	            item.contentType === 'episode' ? 'series' : 'vod';
496	        const openRecentItem = await this.buildStalkerOpenState(
497	            item,
498	            targetId,
499	            fallbackCategory
500	        );
501	
502	        await this.router.navigate(
503	            this.buildPlaylistRoute('stalker', item.playlistId, ['recent']),
504	            {
505	                state: { openRecentItem },
506	            }
507	        );
508	    }
509	
510	    private getPosterKey(item: DownloadItem): string {
511	        return `${item.id}:${item.posterUrl ?? ''}`;
512	    }
513	
514	    private handleFileActionError(error?: string): void {
515	        const message =
516	            error === 'File not found'
517	                ? this.translate.instant('DOWNLOADS.FILE_NOT_FOUND')
518	                : this.translate.instant('DOWNLOADS.FILE_ACTION_ERROR');
519	
520	        this.snackBar.open(message, undefined, {
521	            duration: 3000,
522	            horizontalPosition: 'start',
523	        });
524	    }
525	}
