        height: 24px;
        border-radius: 999px;
        display: inline-flex;
        align-items: center;
        justify-content: center;
        color: var(--mat-sys-on-surface-variant);
        background: color-mix(
            in srgb,
            var(--mat-sys-surface-container-high) 76%,
            transparent
        );
        border: 1px solid
            color-mix(in srgb, var(--mat-sys-outline-variant) 82%, transparent);
        font-size: 0.75rem;
        font-weight: 600;
        line-height: 1;
        white-space: nowrap;
        overflow: hidden;
        text-overflow: ellipsis;
        flex-shrink: 0;
    }

    .search-chip--scope {
        color: var(--mat-sys-on-surface);
    }

    .search-chip--status {
        color: var(--app-selection-color, var(--mat-sys-primary));
        background: color-mix(
            in srgb,
            var(--app-selection-surface, var(--mat-sys-primary-container)) 70%,
            transparent
        );
        border-color: color-mix(
            in srgb,
            var(--app-selection-border, var(--mat-sys-primary)) 52%,
            transparent
        );
    }

    input {
        flex: 1;
        border: none;
        outline: none;
        background: transparent;
        color: var(--mat-sys-on-surface);
        font: inherit;
        font-size: 0.875rem;

        &:disabled {
            cursor: not-allowed;
            opacity: 0.5;
        }

        &::placeholder {
            color: var(--mat-sys-on-surface-variant);
            opacity: 0.7;
        }
    }

    .command-trigger {
        width: 28px;
        height: 28px;
        padding: 0;
        margin-right: -4px;
        color: var(--mat-sys-on-surface-variant);
        border-radius: 8px;
        flex-shrink: 0;

        &:hover {
            background: var(--mat-sys-surface-container-high);
            color: var(--mat-sys-on-surface);
        }

        mat-icon {
            font-size: 16px;
            width: 16px;
            height: 16px;
        }
    }
}

.header-actions {
    display: flex;
    align-items: center;
    gap: 4px;
    app-region: no-drag;

    button,
    a {
        color: var(--mat-sys-on-surface-variant);
        border-radius: 8px;
        transition:
            color 0.15s ease,
            background 0.15s ease;

        &:hover {
            color: var(--mat-sys-on-surface);
            background: var(--mat-sys-surface-container);
        }

        &.is-active {
            color: var(--app-selection-color);
            background: linear-gradient(
                145deg,
                var(--app-selection-surface-strong),
                var(--app-selection-surface)
            );
            box-shadow:
                inset 0 0 0 1px var(--app-selection-border),
                0 10px 20px -16px var(--app-selection-glow);
        }
    }
}

