    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 40px;
    height: 40px;
}

.download-ring {
    position: absolute;
    top: 50%;
    left: 50%;
    width: 44px;
    height: 44px;
    margin: -22px 0 0 -22px;
    border-radius: 50%;
    border-width: 2px;
    border-style: solid;
    border-color: rgba(255, 255, 255, 0.1);
    border-top-color: var(--mat-sys-primary);
    pointer-events: none;
    z-index: 10;
    animation: download-ring-spin 1.2s linear infinite;
}

.download-btn-wrap .has-activity mat-icon {
    animation: download-pulse 2s ease-in-out infinite;
}

@keyframes download-ring-spin {
    to {
        transform: rotate(360deg);
    }
}

@keyframes download-pulse {
    0%,
    100% {
        opacity: 1;
    }

    50% {
        opacity: 0.55;
    }
}

.header-actions-divider {
    width: 1px;
    height: 20px;
    background: var(--mat-sys-outline-variant);
    margin: 0 4px;
    flex-shrink: 0;
    opacity: 0.6;
}

