    .workspace-header {
        padding-inline: 10px;
        gap: 10px;
    }

    .playlist-switcher {
        width: 190px;
    }

    .header-actions {
        gap: 0;
    }

    .search-field {
        gap: 6px;
        padding-inline: 10px;

        .search-chip {
            max-width: 116px;
            padding-inline: 8px;
        }
    }
}

@media (max-width: 640px) {
    .playlist-switcher {
        width: auto;
        min-width: 140px;
        flex: 1;
    }

    .search-field {
        .search-chip--status {
            display: none;
        }
    }
}

