:host {
    display: block;
    min-width: 0;
}

.workspace-header {
    display: flex;
    align-items: center;
    gap: 12px;
    height: 56px;
    padding: 0 24px;
    border-bottom: 1px solid var(--mat-sys-outline-variant);
    background: var(--app-header-bg, var(--mat-sys-surface-container-low));
    app-region: drag;
}

.playlist-switcher {
    width: min(260px, 32vw);
    flex-shrink: 0;
    app-region: no-drag;
}

.search-field {
    flex: 1;
    min-width: 160px;
    height: 36px;
    border-radius: 10px;
    border: 1px solid var(--app-search-border, var(--mat-sys-outline-variant));
    background: var(--app-search-bg, var(--mat-sys-surface-container));
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 0 12px;
    transition:
        border-color 0.15s ease,
        background-color 0.15s ease,
        box-shadow 0.15s ease;
    app-region: no-drag;

    &:focus-within {
        border-color: var(--mat-sys-primary);
        box-shadow: 0 0 0 3px
            color-mix(in srgb, var(--mat-sys-primary) 12%, transparent);
    }

    mat-icon {
        font-size: 18px;
        width: 18px;
        height: 18px;
        color: var(--mat-sys-on-surface-variant);
        flex-shrink: 0;
    }

    .search-chip {
        max-width: 200px;
        padding: 0 10px;
        height: 24px;
        border-radius: 999px;
        display: inline-flex;
        align-items: center;
        justify-content: center;
        color: var(--mat-sys-on-surface-variant);
        background: color-mix(
            in srgb,
            var(--mat-sys-surface-container-high) 76%,
            transparent
        );
        border: 1px solid
            color-mix(in srgb, var(--mat-sys-outline-variant) 82%, transparent);
        font-size: 0.75rem;
        font-weight: 600;
        line-height: 1;
        white-space: nowrap;
        overflow: hidden;
        text-overflow: ellipsis;
        flex-shrink: 0;
    }

    .search-chip--scope {
        color: var(--mat-sys-on-surface);
    }

    .search-chip--status {
        color: var(--app-selection-color, var(--mat-sys-primary));
        background: color-mix(
            in srgb,
            var(--app-selection-surface, var(--mat-sys-primary-container)) 70%,
            transparent
        );
        border-color: color-mix(
            in srgb,
            var(--app-selection-border, var(--mat-sys-primary)) 52%,
            transparent
        );
    }

    input {
        flex: 1;
        border: none;
        outline: none;
        background: transparent;
        color: var(--mat-sys-on-surface);
        font: inherit;
        font-size: 0.875rem;

        &:disabled {
            cursor: not-allowed;
            opacity: 0.5;
        }

        &::placeholder {
            color: var(--mat-sys-on-surface-variant);
            opacity: 0.7;
        }
    }

    .command-trigger {
        width: 28px;
        height: 28px;
        padding: 0;
        margin-right: -4px;
        color: var(--mat-sys-on-surface-variant);
        border-radius: 8px;
        flex-shrink: 0;

        &:hover {
            background: var(--mat-sys-surface-container-high);
            color: var(--mat-sys-on-surface);
        }

        mat-icon {
            font-size: 16px;
            width: 16px;
            height: 16px;
        }
    }
}

.header-actions {
    display: flex;
    align-items: center;
    gap: 4px;
    app-region: no-drag;

    button,
    a {
        color: var(--mat-sys-on-surface-variant);
        border-radius: 8px;
        transition:
            color 0.15s ease,
            background 0.15s ease;

        &:hover {
            color: var(--mat-sys-on-surface);
            background: var(--mat-sys-surface-container);
        }

        &.is-active {
            color: var(--app-selection-color);
            background: linear-gradient(
                145deg,
                var(--app-selection-surface-strong),
                var(--app-selection-surface)
            );
            box-shadow:
                inset 0 0 0 1px var(--app-selection-border),
                0 10px 20px -16px var(--app-selection-glow);
        }
    }
}

