  if (!bar) return 'no bar element';
  const cs = getComputedStyle(bar);
  const after = getComputedStyle(bar, '::after');
  return JSON.stringify({
    bar: { width: cs.width, height: cs.height, bottom: cs.bottom, background: cs.background, overflow: cs.overflow, position: cs.position },
    after: { width: after.width, background: after.background, animation: after.animationName }
  }, null, 2);
})()" 2>&1

