    background: var(--app-search-bg, var(--mat-sys-surface-container));
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 0 12px;
    transition:
        border-color 0.15s ease,
        background-color 0.15s ease,
        box-shadow 0.15s ease;
    app-region: no-drag;

    &:focus-within {
        border-color: var(--mat-sys-primary);
        box-shadow: 0 0 0 3px
            color-mix(in srgb, var(--mat-sys-primary) 12%, transparent);
    }

    mat-icon {
        font-size: 18px;
        width: 18px;
        height: 18px;
        color: var(--mat-sys-on-surface-variant);
        flex-shrink: 0;
    }

    .search-chip {
        max-width: 200px;
        padding: 0 10px;
        height: 24px;
        border-radius: 999px;
        display: inline-flex;
        align-items: center;
        justify-content: center;
        color: var(--mat-sys-on-surface-variant);
        background: color-mix(
            in srgb,
            var(--mat-sys-surface-container-high) 76%,
            transparent
        );
        border: 1px solid
            color-mix(in srgb, var(--mat-sys-outline-variant) 82%, transparent);
        font-size: 0.75rem;
        font-weight: 600;
        line-height: 1;
        white-space: nowrap;
        overflow: hidden;
        text-overflow: ellipsis;
        flex-shrink: 0;
    }

    .search-chip--scope {
        color: var(--mat-sys-on-surface);
    }

    .search-chip--status {
        color: var(--app-selection-color, var(--mat-sys-primary));
        background: color-mix(
            in srgb,
            var(--app-selection-surface, var(--mat-sys-primary-container)) 70%,
            transparent
        );
        border-color: color-mix(
            in srgb,
            var(--app-selection-border, var(--mat-sys-primary)) 52%,
            transparent
        );
    }

    input {
        flex: 1;
        border: none;
        outline: none;
        background: transparent;
        color: var(--mat-sys-on-surface);
        font: inherit;
        font-size: 0.875rem;

        &:disabled {
            cursor: not-allowed;
            opacity: 0.5;
        }

        &::placeholder {
            color: var(--mat-sys-on-surface-variant);
            opacity: 0.7;
        }
