.download-btn-wrap {
    position: relative;
    display: inline-flex;
    align-items: center;
    justify-content: center;
}

.download-activity-bar {
    position: absolute;
    bottom: 2px;
    left: 50%;
    transform: translateX(-50%);
    width: 18px;
    height: 2px;
    border-radius: 1px;
    background: rgba(255, 255, 255, 0.08);
    overflow: hidden;
    pointer-events: none;
    z-index: 10;
}

.download-activity-bar__fill {
    display: block;
    position: absolute;
    top: 0;
    left: -50%;
    width: 50%;
    height: 100%;
    border-radius: inherit;
    background: var(--mat-sys-primary);
    animation: download-bar-slide 1.4s ease-in-out infinite;
}

@keyframes download-bar-slide {
    0% {
        left: -50%;
    }

    50% {
        left: 100%;
    }

    100% {
        left: -50%;
    }
}

